use super::helpers::*;

#[test]
fn test_server_startup_shows_banner() {
    let runner = TestServerRunner::new(E2ETestConfig::human_mode());
    let result = runner.run_server(&["--demo-mode"]);

    result.print_diagnostics();

    // Should show banner on stderr
    assert!(result.stderr_contains("FastMCP"), "Should show server name in banner");

    // stdout should be clean (no rich output)
    assert!(result.stdout_is_valid_jsonrpc(), "stdout must be valid JSON-RPC only");
}

